noncompliant:
resource storageAccount 'Microsoft.Storage/storageAccounts@2021-04-01' = {
  name: 'exampleStorage'
  properties: {
    accessKey: 'hardcoded-access-key' // Sensitive: hard-coded credential
  }
}

compliant:
resource storageAccount 'Microsoft.Storage/storageAccounts@2021-04-01' = {
  name: 'exampleStorage'
  properties: {
    accessKey: parameters('storageAccessKey') // Secure: uses parameter
  }
}
